// ID папки Google Drive с HEIC-фотографиями
// Можно изменить на нужный folder ID
const folderId = '1iEbSMlsHPX6Sg3y0J0znlT47ri78hk9_';

return [{ json: { folderId } }];

// Парсим список файлов из Google Drive API
const response = $input.first().json;
const files = response.files || [];

if (files.length === 0) {
  throw new Error('Не найдено HEIC-файлов в папке');
}

const folderId = $('Set Folder ID').first().json.folderId;

return files.map(file => ({
  json: {
    fileId: file.id,
    fileName: file.name,
    mimeType: file.mimeType,
    parentFolderId: folderId
  }
}));

// Получаем thumbnailLink и скачиваем JPEG-версию изображения
const fileData = $input.first().json;
const thumbnailLink = fileData.thumbnailLink;

if (!thumbnailLink) {
  // Если thumbnailLink нет — пропускаем файл
  return [{
    json: {
      base64Image: null,
      mediaType: 'image/jpeg',
      fileId: $('Split In Batches').first().json.fileId,
      fileName: $('Split In Batches').first().json.fileName,
      parentFolderId: $('Split In Batches').first().json.parentFolderId,
      error: 'No thumbnail available'
    }
  }];
}

// Увеличиваем размер thumbnail до 2048px для лучшего распознавания
const highResUrl = thumbnailLink.replace(/=s\d+$/, '=s2048');

// Скачиваем JPEG через HTTP
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: highResUrl,
  encoding: 'arraybuffer',
  returnFullResponse: false,
});

const base64Image = Buffer.from(response).toString('base64');

return [{
  json: {
    base64Image,
    mediaType: 'image/jpeg',
    fileId: $('Split In Batches').first().json.fileId,
    fileName: $('Split In Batches').first().json.fileName,
    parentFolderId: $('Split In Batches').first().json.parentFolderId
  }
}];

// Парсинг ответа OpenAI
const response = $input.first().json;
let text = '';

try {
  text = response.choices[0].message.content.trim();
} catch (e) {
  text = 'UNKNOWN';
}

// Валидация: 5-7 цифр
const clientId = /^\d{5,7}$/.test(text) ? text : 'UNKNOWN';

const prev = $('Download JPEG Thumbnail').first().json;

return [{
  json: {
    clientId,
    rawResponse: text,
    fileId: prev.fileId,
    fileName: prev.fileName,
    parentFolderId: prev.parentFolderId
  }
}];

// Проверяем существование папки клиента, создаём если нет
const response = $input.first().json;
const files = response.files || [];
const prev = $('Parse Response').first().json;

if (files.length > 0) {
  // Папка уже существует
  return [{
    json: {
      clientFolderId: files[0].id,
      needCreate: false,
      clientId: prev.clientId,
      fileId: prev.fileId,
      fileName: prev.fileName,
      parentFolderId: prev.parentFolderId
    }
  }];
} else {
  // Нужно создать
  return [{
    json: {
      clientFolderId: null,
      needCreate: true,
      clientId: prev.clientId,
      fileId: prev.fileId,
      fileName: prev.fileName,
      parentFolderId: prev.parentFolderId
    }
  }];
}

// Получаем folder ID (из создания или из поиска)
const input = $input.first().json;
let clientFolderId;

// Если папка была создана — берём id из ответа API
if (input.id) {
  clientFolderId = input.id;
} else {
  clientFolderId = input.clientFolderId;
}

// Данные для перемещения файла
const prev = $('Check Folder').first().json;

return [{
  json: {
    clientFolderId,
    clientId: prev.clientId,
    fileId: prev.fileId,
    fileName: prev.fileName,
    parentFolderId: prev.parentFolderId
  }
}];

// Логируем успешное перемещение
const prev = $('Check Folder').first().json;

return [{
  json: {
    timestamp: new Date().toISOString(),
    fileName: prev.fileName,
    fileId: prev.fileId,
    clientId: prev.clientId,
    status: 'SUCCESS'
  }
}];

// Check if UNKNOWN folder exists
const response = $input.first().json;
const files = response.files || [];
const prev = $('Parse Response').first().json;

if (files.length > 0) {
  return [{
    json: {
      unknownFolderId: files[0].id,
      needCreate: false,
      fileId: prev.fileId,
      fileName: prev.fileName,
      parentFolderId: prev.parentFolderId,
      rawResponse: prev.rawResponse
    }
  }];
} else {
  return [{
    json: {
      unknownFolderId: null,
      needCreate: true,
      fileId: prev.fileId,
      fileName: prev.fileName,
      parentFolderId: prev.parentFolderId,
      rawResponse: prev.rawResponse
    }
  }];
}

// Get UNKNOWN folder ID (from creation or search)
const input = $input.first().json;
let unknownFolderId;

if (input.id) {
  unknownFolderId = input.id;
} else {
  unknownFolderId = input.unknownFolderId;
}

const prev = $('Check UNKNOWN Folder').first().json;

return [{
  json: {
    unknownFolderId,
    fileId: prev.fileId,
    fileName: prev.fileName,
    parentFolderId: prev.parentFolderId,
    rawResponse: prev.rawResponse
  }
}];

// Log unknown file moved to UNKNOWN folder
const prev = $('Prepare Move Unknown').first().json;

return [{
  json: {
    timestamp: new Date().toISOString(),
    fileName: prev.fileName,
    fileId: prev.fileId,
    clientId: 'UNKNOWN',
    rawResponse: prev.rawResponse,
    status: 'MOVED_TO_UNKNOWN'
  }
}];

